int maxProfit(int* prices, int n, int fee) {
    int cash = 0, hold = -prices[0];
    for (int i = 1; i < n; i++) {
        int nc = cash > hold + prices[i] - fee ? cash : hold + prices[i] - fee;
        hold = hold > cash - prices[i] ? hold : cash - prices[i];
        cash = nc;
    }
    return cash;
}
